#include <stdio.h>
#include <limits.h>
#define INF (1LL << 60)
#define MAXN 1100
#define MAXM 1100

int n, m;
long long st[MAXN], en[MAXN], ans[MAXN];

struct Edge {
    int u, v;
    long long w;
};

Edge edges[MAXM];

void relax(bool detectNegativeCycle) {
    for (int i = 0; i < m; i++) {
        int u = edges[i].u;
        int v = edges[i].v;
        long long w = edges[i].w;

        if (detectNegativeCycle) {
            if (st[u] > w + st[v])
                st[u] = -INF;

            if (en[v] > w + en[u])
                en[v] = -INF;
        } else {
            if (st[u] > w + st[v])
                st[u] = w + st[v];

            if (en[v] > w + en[u])
                en[v] = w + en[u];
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        scanf("%d %d", &n, &m);

        for (int i = 0; i < n; i++) {
            st[i] = 0;
            en[i] = 0;
        }

        for (int i = 0; i < m; i++) {
            scanf("%d %d %lld", &edges[i].u, &edges[i].v, &edges[i].w);
            edges[i].u--;  // convert to 0-based
            edges[i].v--;
        }

        for (int i = 0; i < 2 * n; i++) {
            relax(false);
        }

        for (int i = 0; i < n; i++) {
            ans[i] = st[i] + en[i];
        }

        for (int i = 0; i < 2 * n; i++) {
            relax(true);
        }

        for (int i = 0; i < n; i++) {
            if (ans[i] == st[i] + en[i]) {
                printf("%lld\n", ans[i]);
            } else {
                printf("INF\n");
            }
        }
    }

    return 0;
}

