import java.io.*;
import java.util.*;

public class Main {

    static final long INF = (long)1e15;

    static class Edge {
        int u, v;
        long w;

        Edge(int u, int v, long w) {
            this.u = u;
            this.v = v;
            this.w = w;
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder output = new StringBuilder();

        int t = Integer.parseInt(br.readLine().trim());

        while (t-- > 0) {
            String[] nm = br.readLine().split(" ");
            int n = Integer.parseInt(nm[0]);
            int m = Integer.parseInt(nm[1]);

            long[] st = new long[n];
            long[] en = new long[n];

            Edge[] edges = new Edge[m];

            for (int i = 0; i < m; i++) {
                String[] line = br.readLine().split(" ");
                int u = Integer.parseInt(line[0]) - 1;
                int v = Integer.parseInt(line[1]) - 1;
                long w = Long.parseLong(line[2]);
                edges[i] = new Edge(u, v, w);
            }

            for (int i = 0; i < 2 * n; i++) {
                for (Edge e : edges) {
                    int u = e.u, v = e.v;
                    long w = e.w;

                    if (st[u] > w + st[v])
                        st[u] = w + st[v];

                    if (en[v] > w + en[u])
                        en[v] = w + en[u];
                }
            }

            long[] ans = new long[n];
            for (int i = 0; i < n; i++) {
                ans[i] = st[i] + en[i];
            }

            for (int i = 0; i < 2 * n; i++) {
                for (Edge e : edges) {
                    int u = e.u, v = e.v;
                    long w = e.w;

                    if (st[u] > w + st[v]) {
                        if (st[u] != -INF)
                            st[u] = -INF;
                    }

                    if (en[v] > w + en[u]) {
                        if (en[v] != -INF)
                            en[v] = -INF;
                    }
                }
            }

            for (int i = 0; i < n; i++) {
                if (ans[i] == st[i] + en[i]) {
                    output.append(ans[i]).append('\n');
                } else {
                    output.append("INF\n");
                }
            }
        }

        System.out.print(output);
    }
}

